import{_ as d,o as r,c as e,a2 as a}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1967年/年中信.md","filePath":"01_letters/1967年/年中信.md"}'),p={name:"01_letters/1967年/年中信.md"};function h(l,t,o,i,_,n){return r(),e("div",null,[...t[0]||(t[0]=[a('<h2 id="_1967年7月12日-上半年业绩报告" tabindex="-1">1967年7月12日 上半年业绩报告 <a class="header-anchor" href="#_1967年7月12日-上半年业绩报告" aria-label="Permalink to &quot;1967年7月12日 上半年业绩报告&quot;">​</a></h2><p>巴菲特合伙有限公司</p><p>地址：内布拉斯加州奥马哈市基维特广场610号，邮编68131</p><p>电话：042-4110</p><p>撰写此信时为6月下旬，家人即将前往加州旅行。为保持过往的时间对称（我尽量克制审美冲动，不在损益表中刻意追求对称），我会预留部分空白，相信填入数据后结论依然合理。</p><p>1967年开局艰难，1月是我们业绩最差的月份之一：合伙公司收益3.3%，道指上涨8.5%。尽管开局不利，上半年我们收益约21%，跑赢道指9.6个百分点。与1966年全年一致，道指依旧是容易超越的基准（不会年年如此，尽管市场普遍认为相反），绝大多数投资经理都跑赢了该指数。以下是常规业绩汇总：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益(1)</th><th>合伙公司业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964</td><td>18.7%</td><td>27.8%</td><td>22.3%</td></tr><tr><td>1965</td><td>14.2%</td><td>47.2%</td><td>36.9%</td></tr><tr><td>1966</td><td>-15.6%</td><td>20.4%</td><td>16.8%</td></tr><tr><td>1967年上半年</td><td>11.4%</td><td>21.0%</td><td>17.3%</td></tr><tr><td>累计收益</td><td>148.3%</td><td>1419.8%</td><td>843.3%</td></tr><tr><td>年化复合收益率</td><td>9.1%</td><td>29.6%</td><td>23.8%</td></tr></tbody></table><ol><li><p>基于道指年度市值变动，加上持有道指成分股当年可获得的股息计算，表格包含合伙公司运营的所有完整年度数据。</p></li><li><p>1957-1961年数据为所有前身有限合伙企业全年运营、扣除所有费用后，向合伙人分配及普通合伙人分成前的合并业绩。</p></li><li><p>1957-1961年数据基于上一列合伙公司业绩，按照现行合伙协议扣除普通合伙人分成后、有限合伙人月度赎回前的收益计算。</p></li></ol><p>上半年合伙公司业绩，未对控股企业进行估值调整，完全来自年初占净资产63.3%的流通证券投资。</p><p>多元化零售公司（DRC）与伯克希尔·哈撒韦公司（B-H）的估值调整，将在12月入伙意向函最终确定前进行，基于当时所有相关标准（含运营、市场、信贷现状）。</p><p>上半年，DRC与B-H均完成重要收购。我们持股80%的DRC及其子公司（霍奇希尔德·科恩、联合棉花商店）整体进展极佳。但B-H的纺织业务面临实际困境，尽管目前未发现底层价值损失，也看不到该业务资产实现良好回报的可能。因此，若道指持续上涨，该板块将显著拖累相对业绩（上半年已如此）。控股型投资在股市大涨时本就容易跑输，叠加业务停滞，拖累更为明显。正如一位朋友所言：<strong>“经验，就是你寻找别的东西时，意外得到的东西。”</strong></p><h3 id="投资公司对比" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h3><p>以下为常规对比数据，对象是两家规模最大、通常95%-100%资金投资于普通股的开放式共同基金，以及两家规模最大的多元化封闭式投资公司。</p><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资信托(1)</th><th>投资者股票基金(1)</th><th>雷曼基金(2)</th><th>三大陆基金(2)</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.7%</td><td>18.3%</td><td>20.6%</td><td>30.5%</td></tr><tr><td>1964</td><td>15.9%</td><td>14.3%</td><td>13.6%</td><td>12.6%</td><td>18.7%</td><td>22.3%</td></tr><tr><td>1965</td><td>10.2%</td><td>9.8%</td><td>19.0%</td><td>10.7%</td><td>14.2%</td><td>36.9%</td></tr><tr><td>1966</td><td>-7.7%</td><td>-10.0%</td><td>-2.6%</td><td>-6.9%</td><td>-15.6%</td><td>16.8%</td></tr><tr><td>1967年上半年</td><td>11.3%</td><td>12.3%</td><td>19.3%</td><td>14.4%</td><td>11.4%</td><td>17.3%</td></tr><tr><td>累计收益</td><td>143.3%</td><td>126.4%</td><td>185.4%</td><td>156.8%</td><td>148.3%</td><td>843.3%</td></tr><tr><td>年化复合收益率</td><td>8.9%</td><td>8.1%</td><td>10.5%</td><td>9.4%</td><td>9.1%</td><td>23.8%</td></tr></tbody></table><ol><li><p>基于资产净值变动，加上当年向在册持有人分配的收益计算。</p></li><li><p>1957-1966年数据来自1967年《穆迪银行与金融手册》，1967年上半年为估算值。</p></li></ol><p>大势，永远比选手更重要。</p>',16)])])}const b=d(p,[["render",h]]);export{c as __pageData,b as default};
